using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;

/// <summary>
/// Banner "MISSÃO CONCLUÍDA" (Sistema de Missões — Missão &gt; Tarefa): overlay
/// (CanvasGroup, Screen Space - Overlay) mostrado brevemente quando
/// <see cref="MissionManager.CompleteMission"/> marca uma missão como
/// concluída pela primeira vez (subscreve <see cref="MissionManager.OnMissionCompleted"/>).
///
/// Toca também <see cref="MissionData.completionMusic"/> (sting curto, via
/// AudioManager.PlaySE — NÃO substitui a música da área, ao contrário do ecrã
/// de SUCESSO/FALHOU dos Desafios: uma missão de NPC acontece "no meio do jogo
/// normal"). Se a missão não tiver "completionMusic" própria, toca
/// "defaultCompletionSfx" (opcional).
///
/// Mensagens recebidas enquanto outra está visível são colocadas numa fila e
/// mostradas em sequência (mesmo padrão de <see cref="PickupPopupUI"/>).
///
/// Singleton com auto-fallback (mesmo padrão de PickupPopupUI/PlayerProgress —
/// funciona mesmo sem UI montada, apenas sem mostrar nada).
///
/// Montagem no Editor:
/// - Canvas (Screen Space - Overlay) com um "panelRoot" (painel central, ex:
///   topo do ecrã) + "canvasGroup" no mesmo GameObject.
/// - "titleText" (TMP_Text, opcional): nome da missão (MissionData.displayName).
/// - "messageText" (TMP_Text): "MISSÃO CONCLUÍDA" ou MissionData.completionMessage.
/// </summary>
public class MissionCompleteUI : MonoBehaviour
{
    public static MissionCompleteUI Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private TMP_Text messageText;

    [Header("Texto Padrão")]
    [Tooltip("Texto mostrado quando \"MissionData.completionMessage\" está vazio.")]
    [SerializeField] private string defaultMessage = "MISSÃO CONCLUÍDA";

    [Header("Áudio")]
    [Tooltip("Som/sting tocado quando a missão concluída não tem \"completionMusic\" própria (opcional). Tocado via AudioManager.PlaySE — não substitui a música da área.")]
    [SerializeField] private AudioClip defaultCompletionSfx;

    [Header("Transição")]
    [Tooltip("Duração do fade in/out, em segundos.")]
    [SerializeField] private float fadeDuration = 0.3f;

    [Tooltip("Tempo (s) com o banner totalmente visível, sem contar o fade.")]
    [SerializeField] private float holdDuration = 2.5f;

    private bool isAutoFallback;
    private bool isShowing;
    private readonly Queue<MissionData> _queue = new Queue<MissionData>();

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null) canvasGroup.alpha = 0f;
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    private void OnEnable()
    {
        MissionManager.OnMissionCompleted += Show;
    }

    private void OnDisable()
    {
        MissionManager.OnMissionCompleted -= Show;
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(MissionCompleteUI) + " (Fallback)");
        var instance = go.AddComponent<MissionCompleteUI>();
        instance.isAutoFallback = true;
    }

    /// <summary>
    /// Mostra o banner "MISSÃO CONCLUÍDA" (ou "mission.completionMessage") para
    /// "mission". Se já houver um banner visível, esta missão é colocada na
    /// fila e mostrada a seguir. Chamado automaticamente por
    /// <see cref="MissionManager.OnMissionCompleted"/>, mas pode também ser
    /// chamado directamente se necessário.
    /// </summary>
    public void Show(MissionData mission)
    {
        if (mission == null) return;

        _queue.Enqueue(mission);
        if (!isShowing) StartCoroutine(ShowQueueRoutine());
    }

    private IEnumerator ShowQueueRoutine()
    {
        isShowing = true;

        while (_queue.Count > 0)
        {
            var mission = _queue.Dequeue();

            if (titleText != null) titleText.text = mission.displayName;

            if (messageText != null)
                messageText.text = !string.IsNullOrEmpty(mission.completionMessage) ? mission.completionMessage : defaultMessage;

            if (AudioManager.Instance != null)
            {
                if (mission.completionMusic != null) AudioManager.Instance.PlaySE(mission.completionMusic);
                else if (defaultCompletionSfx != null) AudioManager.Instance.PlaySE(defaultCompletionSfx);
            }

            // Sem UI montada (instância "Fallback" auto-criada sem montagem no
            // Editor) — apenas espera (mantém o espaçamento entre mensagens),
            // sem overlay. O áudio acima já foi tocado.
            if (canvasGroup == null)
            {
                yield return WaitUnscaled(holdDuration);
                continue;
            }

            if (panelRoot != null) panelRoot.SetActive(true);

            yield return FadeRoutine(0f, 1f);
            yield return WaitUnscaled(holdDuration);
            yield return FadeRoutine(1f, 0f);

            if (panelRoot != null) panelRoot.SetActive(false);
        }

        isShowing = false;
    }

    private IEnumerator WaitUnscaled(float duration)
    {
        float t = 0f;
        while (t < duration)
        {
            t += Time.unscaledDeltaTime;
            yield return null;
        }
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;

        canvasGroup.alpha = from;

        if (fadeDuration <= 0f)
        {
            canvasGroup.alpha = to;
            yield break;
        }

        float t = 0f;
        while (t < fadeDuration)
        {
            t += Time.unscaledDeltaTime;
            canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        canvasGroup.alpha = to;
    }
}
